/**
 * @summary List nearby health centers
 */
export const getListCentersUrl = (params?: ListCentersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/centers?${stringifiedParams}`
    : `/api/centers`;
};

export const listCenters = async (
  params?: ListCentersParams,
  options?: RequestInit,
): Promise<HealthCenter[]> => {
  return customFetch<HealthCenter[]>(getListCentersUrl(params), {
    ...options,
    method: "GET",
  });
};

